import axios, { AxiosInstance, AxiosResponse } from 'axios';

const API_BASE_URL = 'http://localhost:5000/product-types';
const PRODUCTS_API_BASE_URL = 'http://localhost:5000/products';
const VENDORS_API_BASE_URL = 'http://localhost:5000/vendors';
// Vendor Types
export interface Vendor {
  id?: string;
  name: string;
  currency: string;
  contactPerson: string;
  email: string;
  phone: string;
  website: string;
  fax: string;
  description: string;
  doorNumber: string;
  street: string;
  landmark: string;
  city: string;
  postalCode: string;
  state: string;
  country: string;
  created_at?: string;
  updated_at?: string;
}
// Vendor APIs
export const getVendors = (): Promise<AxiosResponse<Vendor[]>> =>
  axios.get(VENDORS_API_BASE_URL);

export const createVendor = (data: Vendor): Promise<AxiosResponse<Vendor>> =>
  axios.post(VENDORS_API_BASE_URL, data);

// Types
export interface ProductType {
  id: string;
  display_name: string;
  api_name: string;
  display_plural_name: string;
  api_plural_name: string | null;
  category: string;
  parent_product_type: string | null;
  asset_type: string;
  asset_category_type: string;
  description: string;
  created_at: string;
  updated_at: string;
}

export interface Product {
  id: string;
  name: string;
  product_type: string | null;
  manufacturer: string | null;
  partNo: string | null;
  cost: string | null;
  description: string | null;
  active: boolean;
  created_at: string;
  updated_at: string;
}

export interface ProductTypeInput {
  display_name: string;
  api_name: string;
  display_plural_name: string;
  api_plural_name: string;
  category: string;
  parent_product_type: string;
  asset_type: string;
  asset_category_type: string;
  description: string;
}

export interface ProductInput {
  name: string;
  product_type: string;
  manufacturer: string;
  part_no: string;
  cost: string;
  description: string;
  active: boolean;
}

// API functions
export const getProductTypes = (): Promise<AxiosResponse<ProductType[]>> => 
  axios.get(API_BASE_URL);

export const getProductType = (id: string): Promise<AxiosResponse<ProductType>> => 
  axios.get(`${API_BASE_URL}/${id}`);

export const createProductType = (data: ProductTypeInput): Promise<AxiosResponse<ProductType>> => 
  axios.post(API_BASE_URL, data);

export const updateProductType = (id: string, data: ProductTypeInput): Promise<AxiosResponse<ProductType>> => 
  axios.put(`${API_BASE_URL}/${id}`, data);

export const deleteProductType = (id: string): Promise<AxiosResponse> => 
  axios.delete(`${API_BASE_URL}/${id}`);

// Product APIs
export const getProducts = (): Promise<AxiosResponse<Product[]>> => 
  axios.get(PRODUCTS_API_BASE_URL);

export const getProduct = (id: string): Promise<AxiosResponse<Product>> => 
  axios.get(`${PRODUCTS_API_BASE_URL}/${id}`);

export const createProduct = (data: ProductInput): Promise<AxiosResponse<Product>> => 
  axios.post(PRODUCTS_API_BASE_URL, data);

export const updateProduct = (id: string, data: ProductInput): Promise<AxiosResponse<Product>> => 
  axios.put(`${PRODUCTS_API_BASE_URL}/${id}`, data);

export const deleteProduct = (id: string): Promise<AxiosResponse> => 
  axios.delete(`${PRODUCTS_API_BASE_URL}/${id}`);
